                            }
                        }
                        else if (xfRow.InsertUpdateOrDelete == DbInsUpdateDelType.Delete)
                        {
                            var rowsToDelete = FMM_UnitConfig_DT.Select($"UnitID = {(int)xfRow.OriginalDataRow["UnitID"]}");
