                                };

                                //BRApi.ErrorLog.LogMessage(si, "cube name: " + row["CubeName"].ToString());

                                var taskActivityItem = BRApi.Utilities.ExecuteDataMgmtSequence(si, workspace_ID, "Run_FMM_Custom_Cube_Calcs", customSubstVars_Dict);
