                                };
                                var taskActivityItem = BRApi.Utilities.ExecuteDataMgmtSequence(si, workspace_ID, "Run_FMM_Consolidation", customSubstVars_Dict);
                            }
                            else if (calcType == "BR_Table_to_Cube")
                            {
