        #region "Extensibility Unbal Helpers"

        private void ExecuteDataBufferCode(int CalcConfigID, ref DataBuffer currCubeBuffer, ref DataBuffer destBuffer, ref DataBuffer clearCubeBuffer, ExpressionDestinationInfo destInfo, string dim1MemName, string dim2MemName, string dim3MemName, string dim4MemName,
            SqlDataReader reader, string bal_buffer_calc, string Unbal_Calc)
        {
            unbal_srcdataBuffers.Clear();
            string memFilterStringPrefix = "|!MemberList_";
            string memFilterStringSuffix = "_Filter.Name!|";

            string src_cell_SQL = @"
							        SELECT Calc_Src_ID_Order, Open_Parens, Math_Operator, Entity, Cons, Scenario,
							            Time, Origin, IC, View, Acct, Flow, UD1, UD2,
							            UD3, UD4, UD5, UD6, UD7, UD8, Calc_Close_Parens,Unbal_Src_Cell_Buffer,
							            Unbal_Origin_Override,Unbal_IC_Override,Unbal_Acct_Override,Unbal_Flow_Override,Unbal_UD1_Override,
										Unbal_UD2_Override,Unbal_UD3_Override,Unbal_UD4_Override,Unbal_UD5_Override,Unbal_UD6_Override,
										Unbal_UD7_Override,Unbal_UD8_Override,Unbal_Src_Cell_Buffer_Filter,OS_Dynamic_Calc_Script,Override_Value,
										Calc_Src_Type
							        FROM MCM_Src_Cell
							        WHERE CalcConfigID = @CalcConfigID
									AND Calc_Src_ID_Order > 1
							        ORDER BY Calc_Src_ID_Order";
            // Prepare and execute the source data query
            var dbConnApp = BRApi.Database.CreateApplicationDbConnInfo(si);
            using (var connection = new SqlConnection(dbConnApp.ConnectionString))
            {
                connection.Open();

                var unbal_srcCommand = new SqlCommand(src_cell_SQL, connection);
                unbal_srcCommand.Parameters.Add(new SqlParameter("@CalcConfigID", SqlDbType.Int) { Value = CalcConfigID });



                var src_buffers = 0;
                var srcCellTable = new DataTable("srcCellTable");

                using (var unbal_srcreader = unbal_srcCommand.ExecuteReader())
                {
                    unbal_srcreader.Read();
                    // setup table with all expected columns
                    for (int i = 0; i < unbal_srcreader.FieldCount; i++)
                    {
                        srcCellTable.Columns.Add(unbal_srcreader.GetName(i));
                    }

                    var member = string.Empty;
                    var calc_srcType = unbal_srcreader["Calc_Src_Type"].ToString();
                    var row = srcCellTable.NewRow();
                    for (int i = 0; i < unbal_srcreader.FieldCount; i++)
                    {
                        string tempstr = unbal_srcreader[i].ToString();
                        //BRApi.ErrorLog.LogMessage(si, "field name: " + unbal_srcreader.GetName(i) + " field val: " + tempstr);
                        if (tempstr.XFContainsIgnoreCase(memFilterStringPrefix))
                        {
                            int listNum = Convert.ToInt16(tempstr.Substring(unbal_srcreader[i].ToString().IndexOf(memFilterStringPrefix) + memFilterStringPrefix.Length, 1));
                            switch (listNum)
                            {
                                case 1:
                                    member = dim1MemName; // passed in member name for dim1
                                    break;
                                case 2:
                                    member = dim2MemName; // passed in member name for dim2
                                    break;
                                case 3:
                                    member = dim3MemName; // passed in member name for dim3
                                    break;
                                case 4:
                                    member = dim4MemName; // passed in member name for dim4
                                    break;
                                _:
                                    break;
                            }
                            tempstr = tempstr.Replace(memFilterStringPrefix + listNum.ToString() + memFilterStringSuffix, member); // member is the member that is passed into the function based on switch statement above
                        }
                        row[unbal_srcreader.GetName(i)] = tempstr;
                    }

                    srcCellTable.Rows.Add(row);

                    int index = Convert.ToInt32(row["Calc_Src_ID_Order"]);
                    src_buffers = index;

                    if (calc_srcType != "Dynamic Calc")
                    {
                        string unbal_srcBuffer = row["Unbal_Src_Cell_Buffer"].ToString();
                        string unbal_srcBufferFilter = row["Unbal_Src_Cell_Buffer_Filter"].ToString();
                        string bufferName = $"SrcBuffer{index}";

                        // Dynamically create and store the data buffer
                        var dataBuffer = api.Data.GetDataBufferUsingFormula($"FilterMembers({unbal_srcBuffer}, {unbal_srcBufferFilter})");
                        //dataBuffer.LogDataBuffer(api, "unbalsrcbuffer?", 500);
                        if (!unbal_srcdataBuffers.ContainsKey(bufferName))
                        {
                            unbal_srcdataBuffers.Add(bufferName, dataBuffer);
                        }
                    }

                    //		            while (unbal_srcreader.Read())
                    //		            {


                    //	                    row["Calc_Src_ID_Order"] = unbal_srcreader["Calc_Src_ID_Order"];
                    //	                    row["Calc_Open_Parens"] = unbal_srcreader["Calc_Open_Parens"];
                    //	                    row["Calc_Math_Operator"] = unbal_srcreader["Calc_Math_Operator"];
                    //	                    row["Entity"] = unbal_srcreader["Entity"];
                    //	                    row["Cons"] = unbal_srcreader["Cons"];
                    //	                    row["Scenario"] = unbal_srcreader["Scenario"];
                    //	                    row["Time"] = unbal_srcreader["Time"];
                    //	                    row["Origin"] = unbal_srcreader["Origin"];
                    //	                    row["IC"] = unbal_srcreader["IC"];
                    //	                    row["View"] = unbal_srcreader["View"];
                    //	                    row["Acct"] = unbal_srcreader["Acct"];
                    //	                    row["Flow"] = unbal_srcreader["Flow"];
                    //	                    row["UD1"] = unbal_srcreader["UD1"];
                    //	                    row["UD2"] = unbal_srcreader["UD2"];
                    //	                    row["UD3"] = unbal_srcreader["UD3"];
                    //	                    row["UD4"] = unbal_srcreader["UD4"];
                    //	                    row["UD5"] = unbal_srcreader["UD5"];
                    //	                    row["UD6"] = unbal_srcreader["UD6"];
                    //	                    row["UD7"] = unbal_srcreader["UD7"];
                    //	                    row["UD8"] = unbal_srcreader["UD8"];
                    //	                    row["Calc_Close_Parens"] = unbal_srcreader["Calc_Close_Parens"];
                    //	                    row["Unbal_Src_Cell_Buffer"] = unbal_srcreader["Unbal_Src_Cell_Buffer"];
                    //	                    row["Unbal_Origin_Override"] = unbal_srcreader["Unbal_Origin_Override"];
                    //	                    row["Unbal_IC_Override"] = unbal_srcreader["Unbal_IC_Override"];
                    //	                    row["Unbal_Acct_Override"] = unbal_srcreader["Unbal_Acct_Override"];
                    //	                    row["Unbal_Flow_Override"] = unbal_srcreader["Unbal_Flow_Override"];
                    //	                    row["Unbal_UD1_Override"] = unbal_srcreader["Unbal_UD1_Override"];
                    //	                    row["Unbal_UD2_Override"] = unbal_srcreader["Unbal_UD2_Override"];
                    //	                    row["Unbal_UD3_Override"] = unbal_srcreader["Unbal_UD3_Override"];
                    //	                    row["Unbal_UD4_Override"] = unbal_srcreader["Unbal_UD4_Override"];
                    //	                    row["Unbal_UD5_Override"] = unbal_srcreader["Unbal_UD5_Override"];
                    //	                    row["Unbal_UD6_Override"] = unbal_srcreader["Unbal_UD6_Override"];
                    //	                    row["Unbal_UD7_Override"] = unbal_srcreader["Unbal_UD7_Override"];
                    //	                    row["Unbal_UD8_Override"] = unbal_srcreader["Unbal_UD8_Override"];
                    //	                    row["Unbal_Src_Cell_Buffer_Filter"] = unbal_srcreader["Unbal_Src_Cell_Buffer_Filter"];
                    //	                    row["OS_Dynamic_Calc_Script"] = unbal_srcreader["OS_Dynamic_Calc_Script"];
                    //	                    row["Override_Value"] = unbal_srcreader["Override_Value"];
                    //	                    row["Calc_Src_Type"] = unbal_srcreader["Calc_Src_Type"];

                    //						srcCellTable.Rows.Add(row);

                    //						int index = (int)unbal_srcreader["Calc_Src_ID_Order"];
                    //						src_buffers = index;

                    //						if (calc_srcType != "Dynamic Calc")
                    //						{	
                    //							string unbal_srcBuffer = unbal_srcreader["Unbal_Src_Cell_Buffer"].ToString();
                    //			                string unbal_srcBufferFilter = unbal_srcreader["Buffer_Filter"].ToString();
                    //			                string bufferName = $"SrcBuffer{index}";

                    //			                // Dynamically create and store the data buffer
                    //			                var dataBuffer = api.Data.GetDataBufferUsingFormula($"FilterMembers({unbal_srcBuffer}, {unbal_srcBufferFilter})");
                    //			                unbal_srcdataBuffers.Add(bufferName, dataBuffer);
                    //						}
                    //					} 
                }

                var destCellTable = new DataTable("destCellTable");

                //setup table with expected columns
                for (int i = 0; i < reader.FieldCount; i++)
                {
                    destCellTable.Columns.Add(reader.GetName(i));
                }


                var destrow = destCellTable.NewRow();
                for (int i = 0; i < reader.FieldCount; i++)
                {
                    string member = "";
                    string tempstr = reader[i].ToString();
                    if (tempstr.XFContainsIgnoreCase(memFilterStringPrefix))
                    {
                        int listNum = Convert.ToInt16(tempstr.Substring(reader[i].ToString().IndexOf(memFilterStringPrefix) + memFilterStringPrefix.Length, 1));
                        switch (listNum)
                        {
                            case 1:
                                member = dim1MemName; // passed in member name for dim1
                                break;
                            case 2:
                                member = dim2MemName; // passed in member name for dim2
                                break;
                            case 3:
                                member = dim3MemName; // passed in member name for dim3
                                break;
                            case 4:
                                member = dim4MemName; // passed in member name for dim4
                                break;
                            _:
                                break;
                        }
                        tempstr = tempstr.Replace(memFilterStringPrefix + listNum.ToString() + memFilterStringSuffix, member); // member is the member that is passed into the function based on switch statement above
                    }
                    destrow[reader.GetName(i)] = tempstr;
                }
                string acct = destrow["Acct"] != DBNull.Value ? destrow["Acct"].ToString() : null;
                string view = destrow["View"] != DBNull.Value ? destrow["View"].ToString() : null;
                string origin = destrow["Origin"] != DBNull.Value ? destrow["Origin"].ToString() : null;
                string ic = destrow["IC"] != DBNull.Value ? destrow["IC"].ToString() : null;
                string flow = destrow["Flow"] != DBNull.Value ? destrow["Flow"].ToString() : null;
                string ud1 = destrow["UD1"] != DBNull.Value ? destrow["UD1"].ToString() : null;
                string ud2 = destrow["UD2"] != DBNull.Value ? destrow["UD2"].ToString() : null;
                string ud3 = destrow["UD3"] != DBNull.Value ? destrow["UD3"].ToString() : null;
                string ud4 = destrow["UD4"] != DBNull.Value ? destrow["UD4"].ToString() : null;
                string ud5 = destrow["UD5"] != DBNull.Value ? destrow["UD5"].ToString() : null;
                string ud6 = destrow["UD6"] != DBNull.Value ? destrow["UD6"].ToString() : null;
                string ud7 = destrow["UD7"] != DBNull.Value ? destrow["UD7"].ToString() : null;
                string ud8 = destrow["UD8"] != DBNull.Value ? destrow["UD8"].ToString() : null;

                List<string> destInfos = new List<string> {
                        acct, view, origin, ic, flow, ud1, ud2, ud3, ud4, ud5, ud6, ud7, ud8
                    };

                for (int i = 0; i < destInfos.Count; i++)
                {
                    string tempstr = destInfos[i];
                    if (tempstr != null && tempstr.Contains("#"))
                    {
                        destInfos[i] = tempstr.Remove(0, tempstr.IndexOf("#") + 1);
                    }
                }

                var os_Curr_Cube_Buffer = destrow["OS_Curr_Cube_Buffer_Filter"].ToString();
                var Buffer = destrow["Buffer_Filter"].ToString();

                //BRApi.ErrorLog.LogMessage(si, "balBufferCalc: " + bal_buffer_calc + " srcbuff: " + Buffer);
                //BRApi.ErrorLog.LogMessage(si, "entity: " + api.Pov.Entity.Name + " time: " + api.Pov.Time.Name);

                var balancedBuffer = api.Data.GetDataBufferUsingFormula($"FilterMembers({bal_buffer_calc},{Buffer})");
                //balancedBuffer.LogDataBuffer(api, "databuffer:",500);
                if (balancedBuffer.DataBufferCells.Values.Count > 0)
                {
                    BRApi.ErrorLog.LogMessage(si, "balancedBuffer cell count: " + balancedBuffer.DataBufferCells.Values.Count);
                    balancedBuffer.LogDataBuffer(api, "balbuffer", 500);
                }

                foreach (var balBuffer_Cell in balancedBuffer.DataBufferCells.Values)
                {
                    //Need to set the Dest Cell correctly so that the clear routine works
                    //			            var destCell = new DataBufferCell(UpdateCellDefinition(balBuffer_Cell, acct, flow, origin,
                    //							ic,ud1,ud2,ud3,ud4,ud5,ud6,ud7,ud8));
                    var destCell = new DataBufferCell(UpdateCellDefinition(balBuffer_Cell, destInfos[0], destInfos[4], destInfos[2],
                        destInfos[3], destInfos[5], destInfos[6], destInfos[7], destInfos[8], destInfos[9], destInfos[10], destInfos[11], destInfos[12]));

                    //						BRApi.ErrorLog.LogMessage(si, "prechange acct: " + destCell.GetAccountName(api));
                    //						destCell.SetAccount(api, acct);
                    //						BRApi.ErrorLog.LogMessage(si, "post acct: " + destCell.GetAccountName(api));

                    BRApi.ErrorLog.LogMessage(si, "dest cell info: " + destCell.DataBufferCellPk.GetMemberScript(api));
                    BRApi.ErrorLog.LogMessage(si, "balbuff cell val: " + balBuffer_Cell.CellAmount);


                    //Call new function, pass in balBuffer_Cell and first unbal src row...  Build up calc string.  Run math  
                    var table = new DataTable();

                    var expression = Unbal_Calc.Replace("BalancedBuffer", balBuffer_Cell.CellAmount.XFToString());
                    //If this is Dynamic Calc, then call Dyn Calc
                    for (int i = 2; i <= src_buffers; i++)
                    {
                        var srcRow = srcCellTable.AsEnumerable().FirstOrDefault(r => Convert.ToInt32(r["Calc_Src_ID_Order"]) == i);
                        if (srcRow != null)
                        {
                            if (srcRow["Calc_Src_Type"].ToString() == "Dynamic Calc")
                            {
                                var dyn_Calc = getdynamic_calc_value(balBuffer_Cell, srcRow);
                                expression = Unbal_Calc.Replace($"DynamicCalc{i}", dyn_Calc.XFToString());

                            }
                            else if (srcRow["Calc_Src_Type"].ToString() == "Stored Cell")
                            {
                                string searchName = $"SrcBuffer{i}";
                                var resultBuffer = new DataBuffer();

                                BRApi.ErrorLog.LogMessage(si, "searching for " + searchName);
                                if (unbal_srcdataBuffers.ContainsKey(searchName))
                                {
                                    // The key was found, and resultBuffer now holds the corresponding DataBuffer
                                    BRApi.ErrorLog.LogMessage(si, "Buffer found for the name: " + searchName);
                                    resultBuffer = unbal_srcdataBuffers.XFGetValue(searchName, resultBuffer);
                                    resultBuffer.LogDataBuffer(api, "result buffer", 500);
                                }

                                var src_buffer_Value = get_src_UnbalBuffer_value(balBuffer_Cell, resultBuffer, srcRow); // this value is currently coming back as 0
                                expression = expression.Replace($"SrcBufferValue{i}", src_buffer_Value.XFToString());

                            }
                        }
                        else
                        {
                            BRApi.ErrorLog.LogMessage(si, "Did not find src row");
                        }
                    }
                    BRApi.ErrorLog.LogMessage(si, "final express: " + expression);
                    // Use the Compute method to evaluate the expression
                    var result = table.Compute(expression, string.Empty);
                    UpdateValue(ref destCell, ref currCubeBuffer, ref destBuffer, Convert.ToDecimal(result));
                    currCubeBuffer.DataBufferCells.Remove(destCell.DataBufferCellPk);
                }
            }
        }
