        #region "Unbalanced Buffer Helpers"

        private decimal getdynamic_calc_value(DataBufferCell balanced_Src_Cell, DataRow srcRow)
        {
            var dyncalc_mbrScriptBuilder = api.Data.CreateMemberScriptBuilder(srcRow["OS_Dynamic_Calc_Script"].ToString());
            api.Data.ApplyDataBufferCellPkToMemberScriptBuilder(dyncalc_mbrScriptBuilder, balanced_Src_Cell.DataBufferCellPk);
            // Apply overrides if they are set
            if (srcRow["Unbal_Origin_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_Origin_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetOrigin(srcRow["Origin"].ToString().Replace("O#", string.Empty));
            }

            if (srcRow["Unbal_IC_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_IC_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetIC(srcRow["IC"].ToString().Replace("IC#", string.Empty));
            }

            if (srcRow["Unbal_Acct_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_Acct_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetAccount(srcRow["Acct"].ToString().Replace("A#", string.Empty));
            }

            if (srcRow["Unbal_Flow_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_Flow_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetFlow(srcRow["Flow"].ToString().Replace("F#", string.Empty));
            }

            if (srcRow["Unbal_UD1_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD1_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD1(srcRow["UD1"].ToString().Replace("UD1#", string.Empty).Replace("U1#", string.Empty));
            }

            if (srcRow["Unbal_UD2_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD2_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD2(srcRow["UD2"].ToString().Replace("UD2#", string.Empty).Replace("U2#", string.Empty));
            }

            if (srcRow["Unbal_UD3_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD3_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD3(srcRow["UD3"].ToString().Replace("UD3#", string.Empty).Replace("U3#", string.Empty));
            }

            if (srcRow["Unbal_UD4_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD4_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD4(srcRow["UD4"].ToString().Replace("UD4#", string.Empty).Replace("U4#", string.Empty));
            }

            if (srcRow["Unbal_UD5_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD5_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD5(srcRow["UD5"].ToString().Replace("UD5#", string.Empty).Replace("U5#", string.Empty));
            }

            if (srcRow["Unbal_UD6_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD6_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD6(srcRow["UD6"].ToString().Replace("UD6#", string.Empty).Replace("U6#", string.Empty));
            }

            if (srcRow["Unbal_UD7_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD7_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD7(srcRow["UD7"].ToString().Replace("UD7#", string.Empty).Replace("U7#", string.Empty));
            }

            if (srcRow["Unbal_UD8_Override"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Unbal_UD8_Override"].ToString()))
            {
                dyncalc_mbrScriptBuilder.SetUD8(srcRow["UD8"].ToString().Replace("UD8#", string.Empty).Replace("U8#", string.Empty));
            }
            var dyncalc_DataCell = api.Data.GetDataCell(dyncalc_mbrScriptBuilder.GetMemberScript());
            return dyncalc_DataCell.CellAmount;
        }

