        private List<Func<DataBufferCell, bool>> get_filter_Conditions(DataBufferCell balanced_Src_Cell, DataRow srcRow)
        {
            var filterConditions = new List<Func<DataBufferCell, bool>>();
            //Origin
            if (srcRow["Origin"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Origin"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetOriginName(api) == balanced_Src_Cell.DataBufferCellPk.GetOriginName(api));
            }
            // Flow
            if (srcRow["Flow"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Flow"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetFlowName(api) == balanced_Src_Cell.DataBufferCellPk.GetFlowName(api));
            }

            // Account
            if (srcRow["Acct"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["Acct"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetAccountName(api) == balanced_Src_Cell.DataBufferCellPk.GetAccountName(api));
            }

            // IC
            if (srcRow["IC"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["IC"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetICName(api) == balanced_Src_Cell.DataBufferCellPk.GetICName(api));
            }

            // UD1
            if (srcRow["UD1"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD1"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD1Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD1Name(api));
            }

            // UD2
            if (srcRow["UD2"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD2"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD2Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD2Name(api));
            }

            // UD3
            if (srcRow["UD3"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD3"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD3Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD3Name(api));
            }

            // UD4
            if (srcRow["UD4"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD4"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD4Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD4Name(api));
            }

            // UD5
            if (srcRow["UD5"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD5"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD5Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD5Name(api));
            }

            // UD6
            if (srcRow["UD6"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD6"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD6Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD6Name(api));
            }

            // UD7
            if (srcRow["UD7"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD7"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD7Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD7Name(api));
            }

            // UD8
            if (srcRow["UD8"] != DBNull.Value && !string.IsNullOrEmpty(srcRow["UD8"].ToString()))
            {
                filterConditions.Add(cell => cell.DataBufferCellPk.GetUD8Name(api) == balanced_Src_Cell.DataBufferCellPk.GetUD8Name(api));
            }

            return filterConditions;
        }

        private List<DataBufferCell> GetFilteredCells(DataBuffer unbal_alloc, params Func<DataBufferCell, bool>[] filterConditions)
        {
            if (unbal_alloc == null || unbal_alloc.DataBufferCells == null)
            {
                return new List<DataBufferCell>(); // Return an empty list if unbal_alloc or DataBufferCells is null
            }

            return unbal_alloc.DataBufferCells.Values
                .Where(cell => filterConditions.All(condition => condition(cell)))
                .ToList();
        }

        private void UpdateExpressionForRow(DataBufferCell balBuffer_Cell, DataRow srcRow, Dictionary<string, DataBuffer> unbal_srcdataBuffers, ref Dictionary<DataBufferCell, string> cell_Expressions, DataBufferCell Cell, int i)
        {
            var acct = string.Empty;
            var flow = string.Empty;
            var origin = string.Empty;
            var ic = string.Empty;
            var ud1 = string.Empty;
            var ud2 = string.Empty;
            var ud3 = string.Empty;
            var ud4 = string.Empty;
            var ud5 = string.Empty;
            var ud6 = string.Empty;
            var ud7 = string.Empty;
            var ud8 = string.Empty;
            // Ensure that there is an entry for this cell in the dictionary
            if (!cell_Expressions.ContainsKey(Cell))
            {
                cell_Expressions[Cell] = string.Empty; // or some initial expression if needed
            }

            // Retrieve the current expression for this cell
            string curr_expression = cell_Expressions[Cell];


            if (srcRow["Calc_Src_Type"].ToString() == "Dynamic Calc")
            {
                var dyn_Calc = getdynamic_calc_value(balBuffer_Cell, srcRow);
                curr_expression = curr_expression.Replace($"DynamicCalc{i}", dyn_Calc.XFToString());
            }
            else if (srcRow["Calc_Src_Type"].ToString() == "Stored Cell")
            {
                string searchName = $"SrcBuffer{i}";
                var resultBuffer = new DataBuffer();

                // Find the buffer corresponding to the search name
                unbal_srcdataBuffers.XFGetValue(searchName, resultBuffer);

                // Get filter conditions based on the source row
                var unbal_alloc_filter_conditions = get_filter_Conditions(balBuffer_Cell, srcRow);

                // Apply the filter conditions to get the relevant cells
                var filtered_Cells = GetFilteredCells(resultBuffer, unbal_alloc_filter_conditions.ToArray());

                // Process the filtered cells
                foreach (var unbal_Alloc_Buffer_Cell in filtered_Cells)
                {
                    if (srcRow["Override_Value"] != DBNull.Value)
                    {
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("A#"))
                        {
                            acct = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetAccountName(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("O#"))
                        {
                            origin = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetOriginName(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("F#"))
                        {
                            flow = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetFlowName(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("IC#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("I#"))
                        {
                            ic = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetICName(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U1#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD1#"))
                        {
                            ud1 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD1Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U2#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD2#"))
                        {
                            ud2 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD2Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U3#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD3#"))
                        {
                            ud3 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD3Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U4#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD4#"))
                        {
                            ud4 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD4Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U5#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD5#"))
                        {
                            ud5 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD5Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U6#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD6#"))
                        {
                            ud6 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD6Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U7#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD7#"))
                        {
                            ud7 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD7Name(api);
                        }
                        if (srcRow["Override_Value"].ToString().XFContainsIgnoreCase("U8#") || srcRow["Override_Value"].ToString().XFContainsIgnoreCase("UD8#"))
                        {
                            ud8 = unbal_Alloc_Buffer_Cell.DataBufferCellPk.GetUD8Name(api);
                        }
                        var unbal_alloc_DestCell = new DataBufferCell(UpdateCellDefinition(Cell, acct, flow, origin,
                                ic, ud1, ud2, ud3, ud4, ud5, ud6, ud7, ud8));
                        curr_expression = cell_Expressions[Cell];
                        curr_expression = curr_expression.Replace($"SrcBuffer{i}", unbal_Alloc_Buffer_Cell.CellAmount.XFToString());
                        cell_Expressions.Add(unbal_alloc_DestCell, curr_expression);


                    }
                }
            }
        }



        #endregion


        #endregion

        #region Utility Functions

        /// <summary>
        /// Retrieves a Member object from a dictionary cache or loads it if not present.
        /// </summary>
        /// <param name="dm">The dimension to query from.</param>
        /// <param name="mbrName">The name of the member to retrieve.</param>
        /// <param name="api">The API instance used to retrieve members if not cached.</param>
        /// <returns>The requested Member object.</returns>
        public Member GetMember(ref Dim dm, string mbrName, ref FinanceRulesApi api)
        {
            string key = dm.Name + ":" + mbrName;
            if (memberDict == null)
                memberDict = new Dictionary<string, Member>();

            if (!memberDict.ContainsKey(key))
                memberDict[key] = api.Members.GetMember(dm.DimPk.DimTypeId, mbrName);

            return memberDict[key];
        }

        #endregion

    }
