using Workspace.OSConsultantTools.FMM_ConfigUI_Assembly;

namespace Workspace.__WsNamespacePrefix.__WsAssemblyName.BusinessRule.DashboardDataSet.FMM_RegPlan_DB_DataSets
{
    public class MainClass
    {
        #region "Global Variables"
        private SessionInfo si;
        private BRGlobals globals;
        private object api;
        private DashboardDataSetArgs args;
        #endregion

        public object Main(SessionInfo si, BRGlobals globals, object api, DashboardDataSetArgs args)
        {
            try
            {
                this.si = si;
                this.globals = globals;
                this.api = api;
                this.args = args;
                switch (args.FunctionType)
                {
                    case DashboardDataSetFunctionType.GetDataSetNames:
                        // var names = new List<string>();
                        // names.Add("MyDataSet");
                        // return names;
                        break;
                    case DashboardDataSetFunctionType.GetDataSet:
                        if (args.DataSetName.XFEqualsIgnoreCase("Get_Gov_PlanCycle_Activity_List"))
                        {
                            return Get_Register_Plan_Activity_List();
                        }
                        else if (args.DataSetName.XFEqualsIgnoreCase("get_FMM_ApprConfigoval_Register_Options"))
                        {
                            var curr_ApprID = Convert.ToInt32(args.CustomSubstVars.XFGetValue("IV_FMM_ApprConfigID", "-1"));
                            var curr_Appr_Step_ID = Convert.ToInt32(args.CustomSubstVars.XFGetValue("IV_FMM_ApprConfig_Step_ID", "-1"));


                            if (curr_ApprID == -1 || curr_Appr_Step_ID == -1)
                            {
                                //find approval and step id through matching step config
                                find_SetApprovalIDs(ref curr_ApprID, ref curr_Appr_Step_ID);
                            }


                            return get_FMM_ApprConfigoval_Register_Options(curr_ApprID, curr_Appr_Step_ID);
                        }
                        break;
                }
                return null;
            }
            catch (Exception ex)
            {
                throw ErrorHandler.LogWrite(si, new XFException(si, ex));
            }
        }

        public DataTable get_FMM_ApprConfigoval_Register_Options(int ApprID, int Appr_Step_ID)
        {
            DataTable dt = new DataTable("FMM_Register_Options");

            var dbConnApp = BRApi.Database.CreateApplicationDbConnInfo(si);
            using (var connection = new SqlConnection(dbConnApp.ConnectionString))
            {
                var sql_Adapter_FMM_ApprConfigoval_Step_Activity_Config = new SQL_Adapter_FMM_ApprConfigoval_Step_Activity_Config(si, connection);
                var sqlDataAdapter = new SqlDataAdapter();

                // Fill DataTable for Approval_Step_Activity_Config
                string selectQuery = @"
                    SELECT Description, Reg_Config_ID
                    FROM FMM_ApprConfigoval_Step_Activity_Config
                    WHERE ApprID = @ApprID
					AND Appr_Step_ID = @Appr_Step_ID";

                var parameters = new SqlParameter[]
                {
                    new SqlParameter("@ApprID", SqlDbType.Int) { Value = ApprID },
                    new SqlParameter("@Appr_Step_ID", SqlDbType.Int) { Value = Appr_Step_ID },

                };

